class Solution:
    def countPaths(self, grid):
        MOD = 10**9 + 7
        m, n = len(grid), len(grid[0])
        total = 0
        # brute DFS counting every strictly increasing path from every start
        def dfs(r, c):
            cnt = 1
            for dr, dc in ((1,0),(-1,0),(0,1),(0,-1)):
                nr, nc = r + dr, c + dc
                if 0 <= nr < m and 0 <= nc < n and grid[nr][nc] > grid[r][c]:
                    cnt += dfs(nr, nc)
            return cnt
        for r in range(m):
            for c in range(n):
                total = (total + dfs(r, c)) % MOD
        return total

